import{_ as c,W as i,X as l,Z as e,$ as o,a0 as t,Y as a,E as r}from"./framework-9a5142fa.js";const h={},n=a('<ul><li><a href="#1-vim">1. vim</a><ul><li><a href="#11-mode">1.1. Mode:</a></li><li><a href="#12-move-the-cursor">1.2. move the cursor</a></li><li><a href="#13-delete">1.3. delete</a><ul><li><a href="#131-delete-the-charater">1.3.1. delete the charater</a></li></ul></li><li><a href="#14-undo">1.4. undo</a></li><li><a href="#15-select">1.5. select</a></li><li><a href="#16-copy">1.6. copy</a></li><li><a href="#17-paste">1.7. paste</a></li><li><a href="#18-search">1.8. search</a></li><li><a href="#19-external-command">1.9. external command</a></li><li><a href="#110-window">1.10. window</a></li><li><a href="#111-save-file">1.11. save file</a></li><li><a href="#112-configuration-file">1.12. configuration file</a></li><li><a href="#113-other">1.13. other</a></li></ul></li></ul><hr><h1 id="_1-vim" tabindex="-1"><a class="header-anchor" href="#_1-vim" aria-hidden="true">#</a> 1. vim</h1><p>vim是vi的加强版(多了个字体颜色)，现在主要使用vim 这两个的命令功能是一样的。你打vi victor.txt和vim victor.txt是一样，等等都一样。</p><h2 id="_1-1-mode" tabindex="-1"><a class="header-anchor" href="#_1-1-mode" aria-hidden="true">#</a> 1.1. Mode:</h2><ul><li><code>Normal Mode</code>: <ul><li><code>&lt;ESC&gt;</code></li></ul></li><li><code>Insert Mode</code>: <ul><li><code>i</code>(insert at the cursor),</li><li><code>a</code>(append below the cursor), e.g.<code>e</code>+<code>a</code>(word),<code>$</code>+<code>a</code>(line).</li><li><code>A</code>(append the cursor line),</li><li><code>o</code>(add a new line below the cursor line and switch into insert mode),</li><li><code>O</code>(likewise, above the cursor line)</li><li><code>R</code>(replace character by character. you can move the cursor by arrow keys, and use Backspace to return the original character)</li></ul></li></ul><h2 id="_1-2-move-the-cursor" tabindex="-1"><a class="header-anchor" href="#_1-2-move-the-cursor" aria-hidden="true">#</a> 1.2. move the cursor</h2><ul><li><code>Any Mode</code>: <ul><li>arrow keys.</li></ul></li><li><code>Normal Mode</code>: <ul><li><code>hl</code>(left and right), <code>jk</code>(down and up).<code>3j</code>, <code>3k</code>, <code>3h</code>, <code>3l</code></li><li><code>gg</code>(the start of file)</li><li><code>G</code>(the last line of file)</li><li><code>20G</code>(the 20th line of file)</li><li><code>ctrl-g</code>(show the location of lines)</li><li><code>50%</code>(the half of the file)</li><li><code>ctrl-u</code>(scroll upward half a window)</li><li><code>ctrl-d</code>(scroll downward half a window)</li><li><code>zz</code>(scroll to make the cursor line in the vertical center of window), <code>zt</code>(the top of window), <code>zb</code>(the bottom of window)</li></ul></li></ul><p>Motion:</p><ul><li><code>w</code>(the start of next the word).<code>2w</code>(2 words forward).<code>2w</code></li><li><code>b</code>(if the cursor is not at the start the word, then move to the start of this word. else previous word). - <code>2b</code></li><li><code>e</code>(if the cursor is not at the end the word, then move to the end of this word. else next word).<code>2e</code></li><li><code>0</code>(the start of the cursor line)</li><li><code>^</code>(the first non-blank character of the cursor line)</li><li><code>$</code>(the end of the cursor line). <code>2$</code>(the end of next cursor line)</li></ul><p>Insert Mode: mouse.(if in the Normal Mode, two ways just move up and down)</p><h2 id="_1-3-delete" tabindex="-1"><a class="header-anchor" href="#_1-3-delete" aria-hidden="true">#</a> 1.3. delete</h2><h3 id="_1-3-1-delete-the-charater" tabindex="-1"><a class="header-anchor" href="#_1-3-1-delete-the-charater" aria-hidden="true">#</a> 1.3.1. delete the charater</h3><ul><li><p><code>Any Mode</code>:</p><ul><li><code>Delete</code>(at the cursor).</li></ul></li><li><p><code>Normal Mode</code>:</p><ul><li><p><code>x</code>(delete the character at the cursor)`.</p></li><li><p><code>J</code>(delete the cursor line break光标出所在行的换行符, join together this line and next line with a space)</p></li><li><p><code>d</code>(delete)+Motion:</p><ul><li><code>dw</code>(delete the characters between at the cursor and before the <code>w</code>), <code>d2w</code></li><li><code>db</code>(delete the characters between at the &#39;e&#39; and before the cursor), <code>d2b</code></li><li><code>de</code>(delete the characters between at the cursor and at the &#39;e&#39;), <code>d2e</code></li><li><code>d0</code>(delete the characters before the cursor)</li><li><code>d$</code>(delete the characters at and below the cursor, and keep the line if the line is empty), or <code>D</code>.</li><li><code>dd</code>(delete the line), <code>2dd</code></li></ul></li><li><p><code>c</code>(delete and switch into insert mode)+Motion:</p><ul><li><code>cw</code>, <code>ce</code>, <code>c0</code>, <code>c$</code>, <code>cc</code></li></ul></li></ul></li><li><p><code>Insert Mode</code>: <code>Backspace</code>(before the cursor)</p></li></ul><h2 id="_1-4-undo" tabindex="-1"><a class="header-anchor" href="#_1-4-undo" aria-hidden="true">#</a> 1.4. undo</h2><ul><li><code>Normal Mode</code>: <ul><li><code>u</code>(back to last change), <code>U</code>(back to original in the whole line, but this is considered a change). a insert mode whatever you type is considered a change.</li><li><code>ctrl-r</code>(to the newer change)</li><li><code>:e!</code>(restore to last saved file, <code>:w</code> is considered.)</li></ul></li></ul><h2 id="_1-5-select" tabindex="-1"><a class="header-anchor" href="#_1-5-select" aria-hidden="true">#</a> 1.5. select</h2><ul><li><code>v</code>(select the highlighte text and the character at the cursor), (<code>o</code> move to the other end). e.g.1.then <code>d</code>(delete the selected text), e.g.2.then <code>:wFILENAME</code>(save the selected text as a file).</li><li><code>ctrl-v</code>(select a rectangular block)</li></ul><h2 id="_1-6-copy" tabindex="-1"><a class="header-anchor" href="#_1-6-copy" aria-hidden="true">#</a> 1.6. copy</h2><ul><li><code>v</code>+<code>y</code>(copy the select)</li><li><code>yw</code>(copy the word), likewise using Motion</li><li><code>yy</code>(copy the cursor line)</li></ul><h2 id="_1-7-paste" tabindex="-1"><a class="header-anchor" href="#_1-7-paste" aria-hidden="true">#</a> 1.7. paste</h2><ul><li><code>p</code>(paste previously deleted text below the cursor, if <code>dd</code> paste that line under this line)(or paste the <code>y</code> ), <code>P</code>(before the cursor)</li><li><code>:r</code>(retrieve), <code>:r FILENAME</code>(paste the content of FILENAME below the cursor line), <code>:r !ls</code>(paste the contend of command ls)</li></ul><h2 id="_1-8-search" tabindex="-1"><a class="header-anchor" href="#_1-8-search" aria-hidden="true">#</a> 1.8. search</h2><p>单个字符：</p><ul><li><code>fa</code>(find forward the character a in the cursor line.). <code>3fa</code></li><li><code>Fa</code>(find backward). <code>3Fa</code></li><li><code>*</code>(grab the cursor word, search next),<code>#</code>(likewise, search last)</li></ul><p>短语：</p><ul><li><p><code>/PHRASE</code>(search PHRASE in the file), <code>n</code>next phrase, <code>N</code>previous phrase, <code>/&lt;Up&gt;&lt;Down&gt;</code>search history, <code>/o&lt;Up&gt;</code>complement certain history,</p><ul><li><code>:set ic</code>(ignor case), <code>set noic</code>(disable ignoring case), or <code>/PHRASE\\c</code>(ignore case).</li><li><code>:set hls</code>(highlight search all phrase), <code>:set nohls</code>(disable).</li><li><code>/\\&lt;the</code>(word starts with &#39;the&#39;)</li><li><code>/the\\&gt;</code>(word ends with &#39;the&#39;)</li><li><code>/^the</code>(beginning of a line)</li><li><code>/the$</code>(end of a line)</li><li><code>/the*</code>(the+other)</li><li><code>/t.e</code>(any single character)</li></ul></li><li><p><code>:s/OLD/NEW</code>(replace OLD to NEW, the first OLD in the line).<code>g</code>(globally, means that multi), <code>c</code>(choice, means that question), <code>%</code>(in the whole file), <code>1,3</code>(the line numbers of the range).e.g.<code>:1,3s/OLD/NEW/g</code>, <code>:%s/OLD/NEW/gc</code></p></li></ul><h2 id="_1-9-external-command" tabindex="-1"><a class="header-anchor" href="#_1-9-external-command" aria-hidden="true">#</a> 1.9. external command</h2><ul><li><code>:!COMMAND</code>(execute the bash command, e.g.<code>ls</code>)</li></ul><h2 id="_1-10-window" tabindex="-1"><a class="header-anchor" href="#_1-10-window" aria-hidden="true">#</a> 1.10. window</h2><ul><li><code>:split</code>(split a window)</li><li><code>ctrl-w ctrl-w</code>(jump from one window to another)</li><li><code>:q</code>(exit window if no changes)</li><li><code>:q!</code>(exit window and discard changes)</li><li><code>:qa</code>(exit all window)</li></ul><h2 id="_1-11-save-file" tabindex="-1"><a class="header-anchor" href="#_1-11-save-file" aria-hidden="true">#</a> 1.11. save file</h2><ul><li><code>:w</code>(save changes)</li><li><code>:w FILENAME</code>(save as a another file)</li><li><code>:wq</code>(save and exit)</li><li><code>ZZ</code>(save and exit)</li></ul><h2 id="_1-12-configuration-file" tabindex="-1"><a class="header-anchor" href="#_1-12-configuration-file" aria-hidden="true">#</a> 1.12. configuration file</h2><ul><li><code>:scriptnames</code>(show file sequence list)</li></ul><p>I edit the file <code>/etc/vim/vimrc.local</code> in root privilege.</p><h2 id="_1-13-other" tabindex="-1"><a class="header-anchor" href="#_1-13-other" aria-hidden="true">#</a> 1.13. other</h2><ul><li><p>match bracket <code>%</code>(move the cursor to the other matching bracket)</p></li><li><p>show line number <code>:set number</code>, <code>:set nonumber</code></p></li></ul><hr>',39),s={href:"https://www.jianshu.com/p/d2e4e377e6c5",target:"_blank",rel:"noopener noreferrer"},u=e("code",null,"man vim",-1);function f(w,p){const d=r("ExternalLinkIcon");return i(),l("div",null,[n,e("p",null,[o("参考： "),e("a",s,[o("编辑器-vi、vim的使用"),t(d)]),u])])}const b=c(h,[["render",f],["__file","vim.html.vue"]]);export{b as default};
